SELECT t, groupArray((category, max_0_PerSecond)) AS groupArr FROM ( SELECT t, category, if((max_0 - lagInFrame(max_0,1,0) OVER ()) < 0 OR lagInFrame(category,1,category) OVER () != category, nan, (max_0 - lagInFrame(max_0,1,0) OVER ()) / (t/1000 - lagInFrame(t/1000,1,0) OVER ())) AS max_0_PerSecond FROM ( SELECT (intDiv(toUInt32(event_time), 30) * 30) * 1000 AS t, category AS category, max(counter) AS max_0 FROM default.test_grafana WHERE event_date >= toDate(1735787045) AND event_date <= toDate(1735790706) AND event_time >= toDateTime(1735787045) AND event_time <= toDateTime(1735790706) GROUP BY t, category ORDER BY category, t)) GROUP BY t ORDER BY t